-- =====================================================================
-- Deepholm Downport  --  23  Gameobject densify (from Neltharion 4.3.4)
-- ---------------------------------------------------------------------
-- Supplements the world with Neltharion's richer GO placement: decoration
-- GOs (type 5) of types we already have + genuinely-missing GO types.
-- EXCLUDES Neltharion-custom (301xxx), seasonal (Midsummer Brazier), and
-- shared FUNCTIONAL types (doors/chests/quest objects we already imported)
-- to avoid duplicating interactive objects. New guid block 9,330,001+.
-- phaseMask=1 (always visible). Missing-type displayIds may need a bake.
-- =====================================================================

DELETE FROM `gameobject_template` WHERE `entry` IN (205353);

DELETE FROM `gameobject` WHERE `guid` BETWEEN 9330001 AND 9330042;
